        step = first_step_to(rx, ry, limit)
        if step is not None:
            md = abs(rx - sx) + abs(ry - sy)
            cand = (md, i, (rx, ry), step)
            if best is None or cand < (best[0], best[1], best[2], best[3]):
                best = (md, i, (rx, ry), step)

    if best is not None:
        dx, dy = best[3]
        return [int(dx), int(dy)]

